    let goodSubarrayCount = 0;

    // R: Map<Value V, Set<Start Index s>> 
    // Stores all distinct OR values V achievable by subarrays ending at the current index i, 
    // mapping V to the set of starting indices s that achieve V.
    let R = new Map();

    // Last: Map<Value V, Last Index P_V>
    // Stores the index of the latest occurrence of value V encountered so far.
    let Last = new Map();

    for (let i = 0; i < N; i++) {
        const Ai = nums[i];
        let R_new = new Map();

        // 1. Extend previous ranges (s < i)
        for (const [V_old, S_old] of R.entries()) {
            const V_new = V_old | Ai;

            if (!R_new.has(V_new)) {
                R_new.set(V_new, new Set());
            }
            const S_new = R_new.get(V_new);

            // Add all starting indices s from the old set
            for (const s of S_old) {
                S_new.add(s);
            }
        }

        // 2. Handle the subarray [i, i]
        const V_single = Ai;
        if (!R_new.has(V_single)) {
            R_new.set(V_single, new Set());
        }
        R_new.get(V_single).add(i);

        // Update R for the current index i
        R = R_new;

        // Update Last occurrence index for Ai
        Last.set(Ai, i);

        // 3. Count good subarrays ending at i
        for (const [V, S] of R.entries()) {
            // Check if V has appeared in nums[0...i]
            if (Last.has(V)) {
                const P_V = Last.get(V);

                // We count how many starting indices s in S satisfy s <= P_V
                let count = 0;
                for (const s of S) {
                    if (s <= P_V) {
                        count++;
                    }
                }
                goodSubarrayCount += count;
            }
        }
    }

    return goodSubarrayCount;
}

